import{bulkPrompt,makeSlideZip,makeZip,n,parseJson,pretty,readiness,slidePrompt,slug}from'./prompting.js';
import{makeSlide,parseStorySets}from'./parser.js';
import{PINTEREST_BOARD_URL,REFERENCE_MODES,applyReferencePlan,buildReferencePlan,parseBoardSnapshot,recommendPinsForSlide,resolveReferenceStrategy}from'./pinterest.js';
import{isConfigured,missingConfig,supabase}from'./supabase.js';
import{authReducer,applyRealtimeEvent,canEdit,isOwner,rowToSlide,rowToStorySet,slideToRow,storySetToRow,revisionKey}from'./db.js';
import*as cloud from'./cloud.js';
import{joinPresence,leavePresence,subscribeToProject,unsubscribeAll,unsubscribeData,updatePresence}from'./realtime.js';

const $=(s,r=document)=>r.querySelector(s),$$=(s,r=document)=>[...r.querySelectorAll(s)];
const steps=['Copy','Review Story','Assets & References','Generate'];
const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const asset=f=>f?{id:`asset-${crypto.randomUUID()}`,file:f,filename:f.name,type:f.type||'application/octet-stream',size:f.size||0}:null;
const stripFile=a=>a&&({id:a.id,filename:a.filename,type:a.type,size:a.size||0,storage_path:a.storage_path||''});
const defaultSet=()=>({id:`set-${crypto.randomUUID()}`,title:'Untitled Story Set',rawStorySetCopy:'',parseStatus:'confirmed',parseWarnings:[],overallDirection:'',slides:[makeSlide(1)],mainAssets:[],references:[],logo:null,pinterestBoardUrl:PINTEREST_BOARD_URL,pinterestPins:[],pinterestSyncedAt:'',pinterestConnected:false,pinterestSnapshotImported:false,referencePlan:null});
const stored=cloud.readLocalProject()||{};
const prefs=JSON.parse(localStorage.getItem('ladytin-ui-prefs')||'{}');
function normaliseSlide(s,i,set){return{...makeSlide(i+1),...s,slide_number:i+1,overlay_text:s.overlay_text??s.copy??'',copy:s.overlay_text??s.copy??'',direction:s.direction??s.art??'',art:s.direction??s.art??'',main:s.main||null,reference:s.reference||null,referenceMode:REFERENCE_MODES.includes(s.referenceMode)?s.referenceMode:(s.reference?'manual_upload':set?.pinterestConnected?'pinterest_auto':'editorial_direction_only'),pinterestPinId:s.pinterestPinId||'',pinterestMatchScore:s.pinterestMatchScore??null,pinterestMatchReason:s.pinterestMatchReason||'',referenceLocked:!!s.referenceLocked}}
function normaliseSet(s){const base={...defaultSet(),...s,bp:undefined,defaultRef:undefined,mainAssets:s.mainAssets||[],references:s.references||[],overallDirection:s.overallDirection||'',pinterestBoardUrl:s.pinterestBoardUrl||PINTEREST_BOARD_URL,pinterestPins:s.pinterestPins||[]};base.slides=(s.slides?.length?s.slides:[makeSlide(1)]).map((x,i)=>normaliseSlide(x,i,base));return base}
function migrate(x){if(Array.isArray(x.storySets)&&x.storySets.length)return x.storySets.map(normaliseSet);if(Array.isArray(x.slides))return[normaliseSet({id:`set-${crypto.randomUUID()}`,title:x.title||'Untitled Story Set',rawStorySetCopy:x.copyDraft||'',slides:x.slides,overallDirection:x.overallDirection||'',mainAssets:[],references:[],logo:x.logo})];return[defaultSet()]}
const state={storySets:[defaultSet()],activeSet:0,activeStep:Math.min(prefs.activeStep||0,3),rawInput:'',parseReview:null,selectedSlide:prefs.selectedSlide||0,pinterestSearch:'',pinterestFilter:''};
let toastTimer;
const current=()=>state.storySets[state.activeSet];

// ---------- cloud session state ----------
const cloudState={view:isConfigured()?'auth':'config',auth:authReducer(undefined,{}),projects:[],project:null,role:'viewer',members:[],invites:[],presence:[],saveState:'saved',conflict:null,inviteToken:null,shareOpen:false,lastInvite:null,migrationResult:null};
const editable=()=>cloudState.view==='studio'&&canEdit(cloudState.role);
const snapshot=new Map();// entity id -> {kind,row JSON,revision,setId}
function snapEntity(kind,id,row,revision,setId){snapshot.set(id,{kind,json:JSON.stringify(row),revision,setId})}
function rebuildSnapshot(){snapshot.clear();for(const set of state.storySets){if(!set.cloudId)continue;snapEntity('story_set',set.id,storySetToRow(set,cloudState.project.id),set.revision||1);for(const s of set.slides)if(s.storySetId||isUuid(s.id))snapEntity('slide',s.id,slideToRow({...s},set.id),s.revision||1,set.id)}}
const isUuid=v=>/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(v||''));
let saveTimer=null,flushing=false,flushQueued=false;
function savePrefs(){localStorage.setItem('ladytin-ui-prefs',JSON.stringify({activeStep:state.activeStep,selectedSlide:state.selectedSlide,activeSet:state.activeSet}))}
function save(immediate=false){
  savePrefs();
  if(!editable())return;
  clearTimeout(saveTimer);
  if(immediate)return void flushSync();
  cloudState.saveState='saving';renderSaveState();
  saveTimer=setTimeout(flushSync,700);
}
function renderSaveState(){const el=$('#saveState');if(el){el.textContent=cloudState.saveState==='saving'?'Saving':cloudState.saveState==='error'?'Error':'Saved';el.className=`save-state ${cloudState.saveState==='error'?'error':cloudState.saveState==='saving'?'saving':''}`}}
async function flushSync(){
  if(!editable())return;
  if(flushing){flushQueued=true;return}
  flushing=true;cloudState.saveState='saving';renderSaveState();
  try{
    const projectId=cloudState.project.id;
    const liveSetIds=new Set(),liveSlideIds=new Set();
    for(const set of state.storySets){
      // New story sets (created by parser confirmation) are inserted first.
      if(!isUuid(set.id)){
        const created=await cloud.insertStorySet(projectId,{...set,sortOrder:state.storySets.indexOf(set)});
        const oldId=set.id;set.id=created.id;set.cloudId=created.id;set.revision=created.revision;
        set.slides.forEach(s=>{s.storySetId=created.id});
        snapEntity('story_set',set.id,storySetToRow(set,projectId),set.revision);
        void oldId;
      }
      set.cloudId=set.id;liveSetIds.add(set.id);
      const setRow=storySetToRow({...set,sortOrder:state.storySets.indexOf(set)},projectId);
      const snap=snapshot.get(set.id);
      if(!snap)snapEntity('story_set',set.id,setRow,set.revision||1);
      else if(snap.json!==JSON.stringify(setRow)){
        const result=await cloud.updateStorySetGuarded(set.id,set.revision||1,setRow);
        if(result.conflict){cloudState.conflict={kind:'story_set',id:set.id,remote:result.remote};continue}
        set.revision=result.row.revision;snapEntity('story_set',set.id,setRow,set.revision);
      }
      // Slides: insert new, update changed, honour order.
      for(const[j,s]of set.slides.entries()){
        s.slide_number=j+1;
        if(!isUuid(s.id)){
          const row=await cloud.insertSlide(set.id,{...s});
          s.id=row.id;s.storySetId=set.id;s.revision=row.revision;
          snapEntity('slide',s.id,slideToRow({...s},set.id),s.revision,set.id);
        }
        liveSlideIds.add(s.id);
        const slideRow=slideToRow({...s},set.id),sn=snapshot.get(s.id);
        if(!sn)snapEntity('slide',s.id,slideRow,s.revision||1,set.id);
        else if(sn.json!==JSON.stringify(slideRow)){
          const result=await cloud.updateSlideGuarded(s.id,s.revision||1,slideRow);
          if(result.conflict){cloudState.conflict={kind:'slide',id:s.id,setId:set.id,remote:result.remote,localRow:slideRow};render();continue}
          s.revision=result.row.revision;s.updated_at=result.row.updated_at;
          snapEntity('slide',s.id,slideRow,s.revision,set.id);
        }
      }
    }
    // Deletions.
    for(const[id,entry]of[...snapshot.entries()]){
      if(entry.kind==='story_set'&&!liveSetIds.has(id)){await cloud.deleteStorySet(id);snapshot.delete(id)}
      if(entry.kind==='slide'&&!liveSlideIds.has(id)&&liveSetIds.has(entry.setId)){await cloud.deleteSlide(id);snapshot.delete(id)}
      if(entry.kind==='slide'&&!liveSetIds.has(entry.setId))snapshot.delete(id);
    }
    cloudState.saveState=cloudState.conflict?'error':'saved';
  }catch(error){
    console.error('Autosave failed:',error);
    cloudState.saveState='error';
    toast(`Could not save: ${error.message}`,'bad');
  }
  flushing=false;renderSaveState();
  if(flushQueued){flushQueued=false;flushSync()}
}
function toast(text,tone='ok'){const el=$('#toast');if(!el)return;el.textContent=text;el.className=`toast show ${tone}`;clearTimeout(toastTimer);toastTimer=setTimeout(()=>el.className='toast',3500)}
async function cp(text,message='JSON copied.'){await navigator.clipboard?.writeText(text);toast(message)}
function dl(name,data,type='application/json'){const a=document.createElement('a');a.href=URL.createObjectURL(data instanceof Blob?data:new Blob([data],{type}));a.download=name;document.body.appendChild(a);a.click();a.remove();setTimeout(()=>URL.revokeObjectURL(a.href),5000)}
const badge=(text,tone='')=>`<span class="badge ${tone}">${esc(text)}</span>`;const btn=(text,id,kind='secondary',attrs='')=>`<button class="btn ${kind}" id="${id}" ${attrs}>${text}</button>`;const field=(label,control,help='')=>`<label class="field"><span>${label}</span>${control}${help?`<small>${help}</small>`:''}</label>`;
function preview(a){if(!a)return'<div class="file-tile empty">No file</div>';if(a.type?.startsWith('image/')&&a.file)return`<img class="thumb" src="${URL.createObjectURL(a.file)}" alt="">`;if(a.type?.startsWith('video/'))return'<div class="file-tile">VIDEO</div>';if(a.type==='application/pdf')return'<div class="file-tile">PDF</div>';return'<div class="file-tile">FILE</div>'}
function pinThumb(pin){return pin?.thumbnail_url?`<img class="pin-thumb" src="${esc(pin.thumbnail_url)}" alt="${esc(pin.title)}" loading="lazy" referrerpolicy="no-referrer">`:'<div class="file-tile">PIN</div>'}
const fullJson=()=>pretty(bulkPrompt(current().slides,current(),current().logo));const rows=()=>readiness(current().slides,current(),current().logo);
function setStep(i){state.activeStep=Math.max(0,Math.min(3,i));save();updatePresence({activity:'viewing',context:steps[state.activeStep]});render();scrollTo({top:0,behavior:'smooth'})}
function progress(){const set=current(),r=rows();return[!!state.rawInput.trim()||set.slides.some(s=>(s.copy||'').trim()),set.parseStatus==='confirmed'&&set.slides.length>0,set.slides.every(s=>s.main&&readiness([s],set,set.logo)[0].reference),r.every(x=>x.ready)]}
function shell(content,title,desc){const done=progress(),set=current();return`<div class="app-shell"><header class="topbar"><div><b>LadyTin Story Studio</b><span class="project-status">${esc(set.title)}</span></div><div class="top-actions">${presenceStrip()}<span id="saveState" class="save-state">Saved</span>${badge(cloudState.role,`role ${cloudState.role}`)}${isOwner(cloudState.role)?btn('Share Project','shareProject'):''}${btn('Projects','backProjects','tertiary')}<select id="setPicker" aria-label="Active story set">${state.storySets.map((s,i)=>`<option value="${i}" ${i===state.activeSet?'selected':''}>${String(i+1).padStart(2,'0')} · ${esc(s.title)}</option>`).join('')}</select>${btn('Save Project','saveProject')}${state.activeStep<3?btn('Continue','continue','primary'):''}</div></header><nav class="stepper" aria-label="Workflow">${steps.map((s,i)=>`<button class="step ${i===state.activeStep?'active':''} ${done[i]?'done':''}" data-step="${i}"><span>${String(i+1).padStart(2,'0')}</span>${s}</button>`).join('')}</nav><main class="page"><div class="page-head"><div><div class="eyebrow">${String(state.activeStep+1).padStart(2,'0')} / 04</div><h1>${title}</h1><p>${desc}</p></div></div>${conflictBar()}${content}</main>${cloudState.shareOpen?shareDialog():''}<div id="toast" class="toast" role="status" aria-live="polite"></div></div>`}
function copyPage(){if(state.parseReview)return reviewParsedPage();const placeholder=`SET 2 — The Journey of a Garment\n\nSlide 1 — It starts on a wall covered in paper. Everything still possible.\n\nSlide 2 — Then it reaches hands in India. Hands that have been stitching this way for generations.\n\nSlide 3 — The smallest details are always added last. That is where everything comes together.\n\nSlide 4 — What reaches you is not just one garment.\nCTA: See where it begins.`;return shell(`<div class="copy-layout"><section class="panel">${field('Paste Complete Story Set Copy',`<textarea id="rawInput" class="copy-editor" placeholder="${esc(placeholder)}">${esc(state.rawInput)}</textarea>`,'Paste one complete set or several SET blocks together. Exact wording is preserved.')}<div class="action-row">${btn('Parse Story Set','parse','primary')}${btn('Insert Slide Break','insertBreak','tertiary')}${btn('Save Draft','saveDraft')}${btn('Clear','clear','tertiary')}</div></section><aside class="panel guidance"><h2>Parser recognises</h2><p>Set titles, slide markers, CTA, Poll, Question, Direction, video/content descriptions, no-text-overlay and caption-CC instructions.</p><ul><li>Copy is never rewritten.</li><li>Several sets can be pasted together.</li><li>Nothing replaces project data until confirmation.</li></ul></aside></div>`,'Copy','Paste the complete story-set copy once, then review the detected structure.')}
function reviewParsedPage(){const review=state.parseReview,active=review.active??0,set=review.sets[active];return shell(`<div class="review-layout"><aside class="panel review-summary"><div class="panel-head"><h2>${review.sets.length} set${review.sets.length===1?'':'s'} detected</h2>${badge(`${review.totalSlides} slides`)}</div>${review.sets.map((s,i)=>`<button class="review-set ${i===active?'active':''} ${s.included===false?'excluded':''}" data-review-set="${i}"><b>${esc(s.title)}</b><small>${s.slides.length} slides · ${s.parseWarnings.length} warnings</small></button>`).join('')}<div class="stack-actions">${btn('Confirm All Included Sets','confirmParsed','primary')}${btn('Re-parse','reparse')}${btn('Return to Raw Copy','backRaw','tertiary')}${btn('Cancel','cancelParse','danger')}</div></aside><section class="panel"><div class="panel-head"><div><div class="eyebrow">Review Parsed Story Set</div><h2>${esc(set.title)}</h2></div><label class="include-check"><input type="checkbox" id="includeSet" ${set.included===false?'':'checked'}> Include set</label></div>${field('Detected set title',`<input id="reviewTitle" value="${esc(set.title)}">`)}${set.parseWarnings.length?`<div class="warning-box">${set.parseWarnings.map(w=>`<p>• ${esc(w)}</p>`).join('')}</div>`:''}<div class="parsed-list">${set.slides.map((s,i)=>`<article class="parsed-row"><div class="parsed-number">${n(i)}</div><div>${field('Exact overlay copy',`<textarea data-review-slide="${i}" data-key="overlay_text">${esc(s.overlay_text)}</textarea>`)}<div class="form-grid">${field('CTA',`<input data-review-slide="${i}" data-key="cta" value="${esc(s.cta)}">`)}${field('Interaction',`<input data-review-slide="${i}" data-key="interaction" value="${esc(s.interaction)}">`)}</div>${field('Content / video description',`<input data-review-slide="${i}" data-key="content_description" value="${esc(s.content_description)}">`)}${field('Direction',`<textarea data-review-slide="${i}" data-key="direction">${esc(s.direction)}</textarea>`)}<div class="check-row"><label><input type="checkbox" data-review-check="${i}" data-key="no_text_overlay" ${s.no_text_overlay?'checked':''}> No text overlay</label><label><input type="checkbox" data-review-check="${i}" data-key="caption_cc" ${s.caption_cc?'checked':''}> Caption CC</label></div></div></article>`).join('')}</div></section></div>`,'Review Parsed Story Set','Check the parser result and correct individual fields before creating project data.')}
function reviewStoryPage(){const set=current(),i=Math.min(state.selectedSlide,set.slides.length-1),s=set.slides[i];return shell(`<div class="set-strip panel"><div><b>${esc(set.title)}</b><small>${set.slides.length} slides · ${set.parseStatus}</small></div>${btn('Re-parse From Original Copy','reparseOriginal','tertiary')}</div><div class="master-detail"><aside class="panel story-list"><div class="panel-head"><h2>Slides</h2>${btn('+ Slide','addSlide','tertiary')}</div>${set.slides.map((x,j)=>`<button class="story-item ${j===i?'active':''}" data-slide="${j}"><span>${n(j)}</span><div><b>${esc((x.copy||x.content_description||`Slide ${j+1}`).slice(0,46))}</b><small>${esc(x.role||'Unassigned')}</small></div></button>`).join('')}</aside><section class="panel detail">${field('Story-set title',`<input id="setTitle" value="${esc(set.title)}">`)}${field('Overall Set Direction — Optional',`<textarea id="overallDirection" placeholder="Keep the complete set soft, tactile and intimate. Use one restrained recurring motif.">${esc(set.overallDirection)}</textarea>`,'Included in set analysis, matching and every prompt.')}<div class="panel-head"><div><div class="eyebrow">Slide ${n(i)}</div><h2>${esc(s.role)}</h2></div><div class="mini-actions">${i>0?btn('Move Up','moveUp','tertiary'):''}${i<set.slides.length-1?btn('Move Down','moveDown','tertiary'):''}${set.slides.length>1?btn('Remove','removeSlide','danger'):''}</div></div><div class="form-grid">${field('Role in story arc',`<select data-slide-field="role"><option>Opening</option><option>Development</option><option>Engagement</option><option>Resolution / CTA</option></select>`)}${field('CTA',`<input data-slide-field="cta" value="${esc(s.cta)}">`)}</div>${field('Exact overlay copy',`<textarea data-slide-field="copy">${esc(s.copy)}</textarea>`)}${field('Interaction',`<input data-slide-field="interaction" value="${esc(s.interaction)}">`)}${field('Content / video direction',`<input data-slide-field="content_description" value="${esc(s.content_description)}">`)}${field('Slide-specific direction — Optional',`<textarea data-slide-field="direction">${esc(s.direction)}</textarea>`)}<div class="check-row"><label><input type="checkbox" data-slide-check="no_text_overlay" ${s.no_text_overlay?'checked':''}> No text overlay</label><label><input type="checkbox" data-slide-check="caption_cc" ${s.caption_cc?'checked':''}> Caption CC</label></div></section></div>`,'Review Story','Review the confirmed copy, story arc, order and optional directions.')}
function uploadBox(id,title,accept,multiple=true){return`<label class="upload-box"><b>${title}</b><small>${accept}</small><input id="${id}" type="file" accept="${accept}" ${multiple?'multiple':''}></label>`}
function library(title,items,type){return`<section class="panel library"><div class="panel-head"><h2>${title}</h2>${badge(`${items.length} files`)}</div><div class="library-grid">${items.length?items.map(a=>{const count=current().slides.filter(s=>(type==='main'?s.main?.id:s.reference?.id)===a.id).length;return`<article class="library-card">${preview(a)}<div><b title="${esc(a.filename)}">${esc(a.filename)}</b><small>${esc(a.type)} · ${count} slide${count===1?'':'s'}</small></div><button class="icon-btn" data-remove-library="${type}:${a.id}" aria-label="Remove ${esc(a.filename)}">×</button></article>`}).join(''):'<p class="empty-copy">No files uploaded yet.</p>'}</div></section>`}
function filteredPins(set){const q=state.pinterestSearch.toLowerCase(),filter=state.pinterestFilter;return set.pinterestPins.filter(pin=>(!q||[pin.title,pin.description,Object.values(pin.visual_tags||{}).flat().join(' ')].join(' ').toLowerCase().includes(q))&&(!filter||Object.values(pin.visual_tags||{}).flat().includes(filter)))}
function pinterestPanel(set){const pins=filteredPins(set),allTags=[...new Set(set.pinterestPins.flatMap(p=>Object.values(p.visual_tags||{}).flat()))].sort();return`<section class="panel pinterest-panel"><div class="panel-head"><div><div class="eyebrow">Primary reference library</div><h2>Pinterest Board</h2><p>${esc(set.pinterestBoardUrl)}</p></div>${set.pinterestConnected?badge('Connected','ok'):set.pinterestSnapshotImported?badge('Snapshot imported','ok'):badge('Not connected')}</div><div class="pinterest-stats"><span>${set.pinterestPins.length} Pins</span><span>${set.pinterestSyncedAt?`Last synced ${new Date(set.pinterestSyncedAt).toLocaleString()}`:'Not synced'}</span></div><div class="action-row">${btn('Connect Pinterest','connectPinterest','primary')}${btn('Sync Board','syncPinterest','secondary',set.pinterestConnected?'':'disabled')}${btn('Recalculate Recommendations','recalculatePins','secondary',set.pinterestPins.length?'':'disabled')}${btn('Disconnect Pinterest','disconnectPinterest','tertiary',set.pinterestConnected?'':'disabled')}</div><div class="snapshot-import">${field('Import Pinterest Board Snapshot',`<textarea id="snapshotText" placeholder='Paste Pinterest JSON export or one Pin URL per line'></textarea>`,'Official OAuth remains the production path. Snapshot import is the supported fallback when API credentials or approval are unavailable.')}<div class="action-row">${btn('Import Snapshot','importSnapshot','secondary')}${uploadBox('snapshotFile','Choose JSON Snapshot','application/json,text/plain',false)}</div></div>${set.pinterestPins.length?`<div class="pin-tools"><input id="pinSearch" value="${esc(state.pinterestSearch)}" placeholder="Search Pins and inferred qualities"><select id="pinFilter"><option value="">All design qualities</option>${allTags.map(t=>`<option ${t===state.pinterestFilter?'selected':''}>${esc(t)}</option>`).join('')}</select></div><div class="pin-grid">${pins.slice(0,60).map(pin=>`<article class="pin-card">${pinThumb(pin)}<div><b>${esc(pin.title)}</b><small>${esc(Object.values(pin.visual_tags||{}).flat().slice(0,5).join(' · '))}</small><p>${esc(pin.design_analysis?.summary||'')}</p><a href="${esc(pin.url)}" target="_blank" rel="noopener">Open Pin</a></div></article>`).join('')}</div>`:''}</section>`}
function recommendationCards(set,s,i){const recs=recommendPinsForSlide(set.pinterestPins,s,set,{usedPins:set.slides.map(x=>x.pinterestPinId).filter(Boolean),adjacentPins:[set.pinterestPins.find(p=>p.id===set.slides[i-1]?.pinterestPinId),set.pinterestPins.find(p=>p.id===set.slides[i+1]?.pinterestPinId)].filter(Boolean)});return`<div class="recommendations"><div class="panel-head"><h3>Recommended for this slide</h3>${badge(`${recs.length} options`)}</div>${recs.length?`<div class="recommend-grid">${recs.map(x=>`<article class="recommend-card ${s.pinterestPinId===x.pin.id?'selected':''}">${pinThumb(x.pin)}<div><b>${esc(x.pin.title)}</b><small>Match ${x.score}/100</small><p>${esc(x.reason)}</p><div class="mini-actions"><button class="btn tertiary" data-use-pin="${i}:${x.pin.id}">Use this reference</button><a class="btn tertiary" href="${esc(x.pin.url)}" target="_blank" rel="noopener">Open Pin</a></div></div></article>`).join('')}</div>`:'<p class="empty-copy">No genuinely suitable Pin cleared the threshold. Original Editorial Direction will be used.</p>'}</div>`}
function referenceModeLabel(mode){return({pinterest_auto:'Pinterest Auto',pinterest_selected:'Pinterest Selected',manual_upload:'Manual reference',editorial_direction_only:'Original editorial direction'})[mode]||mode}
function assetsPage(){const set=current();return shell(`${pinterestPanel(set)}<div class="upload-workspace panel"><div>${uploadBox('uploadMain','Upload Main Assets','image/jpeg,image/png,image/webp,image/heic,image/gif,video/mp4,video/quicktime,video/x-m4v')}</div><div>${uploadBox('uploadRefs','Upload Manual References','image/jpeg,image/png,image/webp,application/pdf')}</div></div><div class="libraries">${library('Main Asset Library',set.mainAssets,'main')}${library('Manual Reference Library',set.references,'ref')}</div><section class="assignments"><div class="section-title"><h2>Slide Assignments</h2><p>Assign a source asset and choose one of four reference modes.</p></div>${set.slides.map((s,i)=>{const strategy=resolveReferenceStrategy(s,i,set.slides,set),ready=readiness([s],set,set.logo)[0];return`<article class="assignment"><div class="assignment-head"><div><div class="eyebrow">Slide ${n(i)} · ${esc(s.role)}</div><b>${esc((s.copy||s.content_description||'No visible copy').slice(0,105))}</b></div><div>${badge(referenceModeLabel(strategy.mode),strategy.mode==='editorial_direction_only'?'':'ok')} ${s.referenceLocked?badge('Locked'):''} ${ready.ready?badge('Ready','ok'):badge('Incomplete','bad')}</div></div><div class="assignment-grid"><div>${field('Main asset',`<select data-assign-main="${i}"><option value="">Select main asset…</option>${set.mainAssets.map(a=>`<option value="${a.id}" ${s.main?.id===a.id?'selected':''}>${esc(a.filename)}</option>`).join('')}</select>`)}${preview(s.main)}</div><div>${field('Reference Mode',`<select data-reference-mode="${i}">${REFERENCE_MODES.map(m=>`<option value="${m}" ${s.referenceMode===m?'selected':''}>${referenceModeLabel(m)}</option>`).join('')}</select>`)}${s.referenceMode==='manual_upload'?field('Manual reference',`<select data-assign-ref="${i}"><option value="">Select manual reference…</option>${set.references.map(a=>`<option value="${a.id}" ${s.reference?.id===a.id?'selected':''}>${esc(a.filename)}</option>`).join('')}</select>`):''}${s.referenceMode==='manual_upload'?preview(s.reference):strategy.source==='pinterest'?pinThumb(set.pinterestPins.find(p=>p.id===strategy.pinterest_pin_id)||{}):`<div class="editorial-summary"><b>${esc(strategy.original_editorial_direction?.concept_title||'Original editorial direction')}</b><p>${esc(strategy.original_editorial_direction?.composition||'')}</p></div>`}<div class="mini-actions"><button class="btn tertiary" data-lock-ref="${i}">${s.referenceLocked?'Unlock reference':'Lock reference'}</button><button class="btn tertiary" data-clear-ref="${i}">Clear selection</button></div></div><div>${field('Slide-specific direction — Optional',`<textarea data-assignment-direction="${i}">${esc(s.direction)}</textarea>`)}${strategy.match_reason?`<p class="match-reason">${esc(strategy.match_reason)}</p>`:''}</div></div>${set.pinterestPins.length&&['pinterest_auto','pinterest_selected'].includes(s.referenceMode)?recommendationCards(set,s,i):''}</article>`}).join('')}</section>`,'Assets & References','Use Pinterest recommendations, a selected Pin, a manual reference or an original editorial direction.')}
function generatePage(){const set=current(),r=rows(),ready=r.every(x=>x.ready),full=fullJson();return shell(`<section class="panel"><div class="panel-head"><div><h2>Story-set readiness</h2><p>${r.filter(x=>x.ready).length} of ${r.length} slides ready</p></div>${ready?badge('Ready','ok'):badge('Blocked','bad')}</div><div class="table-wrap"><table><thead><tr><th>Slide</th><th>Main Asset</th><th>Reference Strategy</th><th>JSON</th><th>Ready</th></tr></thead><tbody>${r.map(x=>`<tr><td>${n(x.slide-1)}</td><td>${x.main?'Ready':'Missing'}</td><td>${esc(referenceModeLabel(x.referenceMode))}</td><td>${x.json?'Valid':'Invalid'}</td><td>${x.ready?badge('Ready','ok'):`<span class="missing">${esc(x.missing.join(', '))}</span>`}</td></tr>`).join('')}</tbody></table></div></section><section class="panel bulk-panel"><div><div class="eyebrow">Complete story set</div><h2>${esc(set.title)}</h2><p>${set.slides.length} slides · JSON ${parseJson(full).ok?'valid':'invalid'}</p></div><div class="bulk-actions">${btn('Copy Full Story-Set JSON','copyFull','primary')}${btn('Download Full Story-Set JSON','downloadFull')}${btn('Download Full Story-Set ZIP','downloadZip','primary',ready?'':'disabled')}${btn('Download Incomplete Draft Package','downloadDraft','tertiary')}</div></section><div class="section-title"><h2>Individual slides</h2><p>Every prompt includes story role, exact copy, reference strategy, selected visual logic and continuity.</p></div><div class="production-grid">${set.slides.map((s,i)=>{const x=r[i],json=pretty(slidePrompt(s,i,set.slides,set,set.logo)),strategy=resolveReferenceStrategy(s,i,set.slides,set);return`<article class="production-card"><div class="card-top"><div><div class="eyebrow">Slide ${n(i)}</div><b>${esc(s.role)}</b></div>${x.ready?badge('Ready','ok'):badge('Blocked','bad')}</div><div class="preview-pair"><div>${preview(s.main)}<small>Source</small></div><div>${strategy.source==='pinterest'?pinThumb(set.pinterestPins.find(p=>p.id===strategy.pinterest_pin_id)||{}):strategy.mode==='manual_upload'?preview(s.reference):'<div class="file-tile">EDITORIAL</div>'}<small>${esc(referenceModeLabel(strategy.mode))}</small></div></div><p class="copy-excerpt">${esc(s.copy||s.content_description||'No visible overlay copy')}</p><p class="match-reason">${esc(strategy.match_reason||strategy.original_editorial_direction?.narrative_intention||'')}</p><div class="card-actions"><button class="btn tertiary" data-action="copyPrompt" data-i="${i}">Copy Prompt</button><button class="btn tertiary" data-action="copy" data-i="${i}">Copy JSON</button><button class="btn tertiary" data-action="json" data-i="${i}">Download JSON</button><button class="btn tertiary" data-action="package" data-i="${i}">Download Slide Package</button><button class="btn tertiary" data-action="recalculate" data-i="${i}">Regenerate Recommendations</button><button class="btn tertiary" data-action="view" data-i="${i}">View JSON</button></div><details id="json-${i}" class="json-panel"><summary>Slide JSON</summary><pre>${esc(json)}</pre></details></article>`}).join('')}</div>`,'Generate','Validate and export individual slides or the complete story set.')}
function configPage(){return`<div class="auth-shell"><div class="auth-card"><h1>LadyTin Story Studio</h1><p>Cloud collaboration is not configured for this build yet.</p><p>Set these environment variables and rebuild:</p><ul class="config-list">${missingConfig().map(k=>`<li>${k}</li>`).join('')}</ul><p class="auth-note">Locally: copy .env.example to .env, fill the values and run npm run build. On Vercel: add them as project environment variables.</p></div></div>`}
function authPage(){const a=cloudState.auth;return`<div class="auth-shell"><div class="auth-card"><h1>LadyTin Story Studio</h1><p>Sign in with your email. You will receive a one-time magic link.</p>${cloudState.inviteToken?'<p class="viewer-note">You are accepting a project invitation. Sign in with the email address the invitation was sent to.</p>':''}${field('Email address',`<input id="authEmail" type="email" autocomplete="email" placeholder="you@example.com" value="">`)}<div class="action-row">${btn(a.status==='loading'?'Please wait…':'Send Magic Link','sendLink','primary',a.status==='loading'?'disabled':'')}</div>${a.status==='link_sent'?'<p class="auth-note">Check your inbox and open the link on this device.</p>':''}${a.error?`<p class="auth-note" style="color:var(--bad)">${esc(a.error)}</p>`:''}</div></div>`}
function projectsPage(){const migratable=!cloud.migrationComplete()&&(Array.isArray(stored.storySets)&&stored.storySets.length||Array.isArray(stored.slides)&&stored.slides.length);return`<div class="projects-page"><div class="panel-head"><div><h1>Projects</h1><p>${esc(cloudState.auth.user?.email||'')}</p></div><div class="mini-actions">${btn('New Project','newProject','primary')}${btn('Sign Out','signOut','tertiary')}</div></div>${cloudState.projects.length?cloudState.projects.map(p=>`<div class="project-row"><div><b>${esc(p.title)}</b><small>Updated ${new Date(p.updated_at).toLocaleString()}</small></div><div class="mini-actions">${btn('Open',`open-${p.id}`,'secondary',`data-open-project="${p.id}"`)}${p.ownerId===cloudState.auth.user?.id?btn('Rename',`ren-${p.id}`,'tertiary',`data-rename-project="${p.id}"`)+btn('Delete',`del-${p.id}`,'danger',`data-delete-project="${p.id}"`):''}</div></div>`).join(''):'<p class="empty-copy">No projects yet. Create your first project.</p>'}${migratable?`<div class="migrate-box"><b>Import this browser’s existing LadyTin project</b><p>Your earlier browser-local project can be moved into the cloud. Files whose original bytes are no longer in this browser session are imported as metadata and must be re-uploaded.</p><div class="action-row">${btn('Import Browser Project','migrateLocal','secondary')}</div></div>`:''}${cloudState.migrationResult?.warnings?.length?`<div class="warning-box">${cloudState.migrationResult.warnings.map(w=>`<p>• ${esc(w)}</p>`).join('')}</div>`:''}</div>`}
function loadingPage(message){return`<div class="auth-shell"><div class="auth-card"><h1>LadyTin Story Studio</h1><p>${esc(message)}</p></div></div>`}
function shareDialog(){const owner=isOwner(cloudState.role);return`<div class="share-dialog" id="shareDialog"><div class="share-card"><div class="panel-head"><h2>Share Project</h2>${btn('Close','closeShare','tertiary')}</div>${cloudState.members.map(m=>`<div class="member-row"><div><b>${esc(m.invited_email||(m.user_id===cloudState.auth.user?.id?cloudState.auth.user.email:`Member ${m.user_id.slice(0,8)}`))}</b> ${m.user_id===cloudState.auth.user?.id?'<small>(you)</small>':''}<small> · ${esc(m.role)}</small></div>${owner&&m.role!=='owner'?`<div class="mini-actions"><select data-member-role="${m.user_id}"><option value="editor" ${m.role==='editor'?'selected':''}>editor</option><option value="viewer" ${m.role==='viewer'?'selected':''}>viewer</option></select>${btn('Remove',`rm-${m.user_id}`,'danger',`data-remove-member="${m.user_id}"`)}</div>`:''}</div>`).join('')}${owner?`<div style="margin-top:16px">${field('Invite by email',`<input id="inviteEmail" type="email" placeholder="collaborator@example.com">`)}${field('Role',`<select id="inviteRole"><option value="editor">editor</option><option value="viewer">viewer</option></select>`)}<div class="action-row">${btn('Create Invitation','createInvite','primary')}</div>${cloudState.lastInvite?`<div class="invite-link">Share this link (expires ${new Date(cloudState.lastInvite.expires_at).toLocaleDateString()}):<br>${esc(cloudState.lastInvite.url)}</div><div class="action-row" style="margin-top:8px">${btn('Copy Invite Link','copyInvite','secondary')}</div>`:''}${cloudState.invites.length?`<p class="auth-note">${cloudState.invites.length} pending invitation${cloudState.invites.length===1?'':'s'}.</p>`:''}</div>`:'<p class="auth-note">Only the project owner can manage members.</p>'}</div></div>`}
function conflictBar(){const c=cloudState.conflict;if(!c)return'';return`<div class="conflict-bar"><span>This slide was updated by another collaborator. Reload the latest version or overwrite it.</span>${btn('Reload latest','conflictReload','secondary')}${btn('Overwrite','conflictOverwrite','danger')}</div>`}
function presenceStrip(){const others=cloudState.presence.filter(p=>p.user_id!==cloudState.auth.user?.id);if(!others.length)return'';return`<div class="presence-strip">${others.slice(0,4).map(p=>`<span class="presence-chip">${esc(p.name)} is ${esc(p.activity||'viewing')} ${esc(p.context||'')}</span>`).join('')}</div>`}
function render(){
  const root=$('#root');
  if(cloudState.view==='config')return void(root.innerHTML=configPage());
  if(cloudState.view==='auth'){root.innerHTML=authPage();return wireAuth()}
  if(cloudState.view==='loading')return void(root.innerHTML=loadingPage('Restoring your session…'));
  if(cloudState.view==='loadingProject')return void(root.innerHTML=loadingPage('Opening project…'));
  if(cloudState.view==='projects'){root.innerHTML=projectsPage();return wireProjects()}
  const views=[copyPage,reviewStoryPage,assetsPage,generatePage];
  root.innerHTML=views[state.activeStep]();
  wire();
  applyViewerMode();
  renderSaveState();
}
function applyViewerMode(){
  if(cloudState.role!=='viewer'||cloudState.view!=='studio')return;
  const note=document.createElement('div');note.className='viewer-note';note.textContent='You have viewer access. Content is read-only, and JSON and ZIP downloads remain available.';
  $('.page')?.prepend(note);
  $$('input,textarea,select').forEach(el=>{if(!['setPicker','pinSearch','pinFilter'].includes(el.id))el.disabled=true});
  const allowIds=new Set(['copyFull','downloadFull','downloadZip','downloadDraft','continue','backProjects','signOut','shareProject','closeShare']);
  const allowActions=new Set(['copyPrompt','copy','json','package','view']);
  $$('button').forEach(b=>{if(b.dataset.step!==undefined||b.dataset.slide!==undefined||allowIds.has(b.id)||allowActions.has(b.dataset.action))return;b.style.display='none'});
}
function parseNow(){if(!state.rawInput.trim())return toast('Paste complete story-set copy first.','bad');const result=parseStorySets(state.rawInput);state.parseReview={...result,active:0};render()}
function confirmReview(){const sets=state.parseReview.sets.filter(s=>s.included!==false).map(normaliseSet);if(!sets.length)return toast('Include at least one story set.','bad');sets.forEach(s=>s.parseStatus='confirmed');state.storySets=sets;state.activeSet=0;state.selectedSlide=0;state.parseReview=null;state.activeStep=1;save(true);render();toast(`${sets.length} story set${sets.length===1?'':'s'} created.`)}
function recalcSet(){const set=current();if(!set.pinterestPins.length){set.slides.forEach(s=>{if(!s.referenceLocked&&!s.reference){s.referenceMode='editorial_direction_only';s.pinterestPinId=''}});save(true);return toast('No Pinterest library is available. Editorial Direction Only has been applied.')}applyReferencePlan(set,buildReferencePlan(set,set.pinterestPins));save(true);render();toast('Pinterest recommendations recalculated for the complete set.')}
async function importSnapshotText(text){const pins=parseBoardSnapshot(text,current().pinterestBoardUrl);if(!pins.length)throw new Error('No valid Pins were found in the snapshot.');const byId=new Map(current().pinterestPins.map(p=>[p.id,p]));pins.forEach(p=>byId.set(p.id,p));const merged=[...byId.values()];state.storySets.forEach(set=>{set.pinterestPins=merged;set.pinterestSnapshotImported=true;set.pinterestSyncedAt=new Date().toISOString()});if(editable()){if(!isUuid(current().id))await flushNow();await cloud.upsertPins(cloudState.project.id,pins)}recalcSet()}
function wire(){
$('#saveProject')?.addEventListener('click',()=>{save();toast('Project saved.')});$('#continue')?.addEventListener('click',()=>setStep(state.activeStep+1));$('#setPicker')?.addEventListener('change',e=>{state.activeSet=+e.target.value;state.selectedSlide=0;save();render()});$$('[data-step]').forEach(b=>b.onclick=()=>setStep(+b.dataset.step));$('#rawInput')?.addEventListener('input',e=>{state.rawInput=e.target.value;save()});$('#parse')?.addEventListener('click',parseNow);$('#insertBreak')?.addEventListener('click',()=>{const t=$('#rawInput'),start=t.selectionStart;state.rawInput=state.rawInput.slice(0,start)+'\n\nSLIDE BREAK\n\n'+state.rawInput.slice(t.selectionEnd);render()});$('#saveDraft')?.addEventListener('click',()=>{save();toast('Draft saved.')});$('#clear')?.addEventListener('click',()=>{state.rawInput='';save();render()});
$$('[data-review-set]').forEach(b=>b.onclick=()=>{state.parseReview.active=+b.dataset.reviewSet;render()});$('#includeSet')?.addEventListener('change',e=>{state.parseReview.sets[state.parseReview.active].included=e.target.checked;render()});$('#reviewTitle')?.addEventListener('input',e=>state.parseReview.sets[state.parseReview.active].title=e.target.value);$$('[data-review-slide]').forEach(el=>el.oninput=e=>{const s=state.parseReview.sets[state.parseReview.active].slides[+el.dataset.reviewSlide];s[el.dataset.key]=e.target.value;if(el.dataset.key==='overlay_text')s.copy=e.target.value;if(el.dataset.key==='direction')s.art=e.target.value});$$('[data-review-check]').forEach(el=>el.onchange=e=>state.parseReview.sets[state.parseReview.active].slides[+el.dataset.reviewCheck][el.dataset.key]=e.target.checked);$('#confirmParsed')?.addEventListener('click',confirmReview);$('#reparse')?.addEventListener('click',parseNow);$('#backRaw')?.addEventListener('click',()=>{state.parseReview=null;render()});$('#cancelParse')?.addEventListener('click',()=>{state.parseReview=null;render()});
$('#setTitle')?.addEventListener('input',e=>{current().title=e.target.value;save()});$('#overallDirection')?.addEventListener('input',e=>{current().overallDirection=e.target.value;save()});$('#reparseOriginal')?.addEventListener('click',()=>{if(confirm('Re-parsing may replace manual copy edits. Continue?')){state.rawInput=current().rawStorySetCopy||state.rawInput;state.activeStep=0;parseNow()}});$$('[data-slide]').forEach(b=>b.onclick=()=>{state.selectedSlide=+b.dataset.slide;updatePresence({activity:'viewing',context:`Slide ${n(state.selectedSlide)}`});savePrefs();render()});$('[data-slide-field="role"]')&&($('[data-slide-field="role"]').value=current().slides[state.selectedSlide].role);$$('[data-slide-field]').forEach(el=>el.oninput=e=>{const s=current().slides[state.selectedSlide],k=el.dataset.slideField;s[k]=e.target.value;if(k==='copy')s.overlay_text=e.target.value;if(k==='direction')s.art=e.target.value;save()});$$('[data-slide-check]').forEach(el=>el.onchange=e=>{current().slides[state.selectedSlide][el.dataset.slideCheck]=e.target.checked;save()});$('#addSlide')?.addEventListener('click',()=>{current().slides.push(normaliseSlide(makeSlide(current().slides.length+1),current().slides.length,current()));state.selectedSlide=current().slides.length-1;save(true);render()});$('#removeSlide')?.addEventListener('click',()=>{current().slides.splice(state.selectedSlide,1);current().slides.forEach((s,i)=>s.slide_number=i+1);state.selectedSlide=Math.max(0,state.selectedSlide-1);save(true);render()});$('#moveUp')?.addEventListener('click',()=>{const a=current().slides,i=state.selectedSlide;[a[i-1],a[i]]=[a[i],a[i-1]];state.selectedSlide--;a.forEach((s,j)=>s.slide_number=j+1);save(true);render()});$('#moveDown')?.addEventListener('click',()=>{const a=current().slides,i=state.selectedSlide;[a[i+1],a[i]]=[a[i],a[i+1]];state.selectedSlide++;a.forEach((s,j)=>s.slide_number=j+1);save(true);render()});
const addFiles=(input,key)=>input?.addEventListener('change',async e=>{const files=[...e.target.files];if(!files.length)return;if(!editable())return toast('You have viewer access to this project.','bad');try{if(!isUuid(current().id))await flushNow();for(const f of files){const uploaded=await cloud.uploadAsset({projectId:cloudState.project.id,storySetId:current().id,file:f,assetType:key==='mainAssets'?'main':'reference',userId:cloudState.auth.user.id});current()[key].push(uploaded)}save(true);render();toast(`${files.length} file${files.length===1?'':'s'} uploaded to project storage.`)}catch(error){console.error(error);toast(error.message,'bad');render()}});addFiles($('#uploadMain'),'mainAssets');addFiles($('#uploadRefs'),'references');$$('[data-remove-library]').forEach(b=>b.onclick=async()=>{const[type,id]=b.dataset.removeLibrary.split(':'),key=type==='main'?'mainAssets':'references';const target=current()[key].find(a=>a.id===id);current()[key]=current()[key].filter(a=>a.id!==id);current().slides.forEach(s=>{if(type==='main'&&s.main?.id===id){s.main=null;s.assetId=''}if(type==='ref'&&s.reference?.id===id){s.reference=null;s.referenceId=''}});try{if(target?.storage_path)await cloud.deleteAsset(target)}catch(error){toast(error.message,'bad')}save(true);render()});$$('[data-assign-main]').forEach(el=>el.onchange=e=>{const i=+el.dataset.assignMain;current().slides[i].main=current().mainAssets.find(a=>a.id===e.target.value)||null;current().slides[i].assetId=e.target.value;save(true);render()});$$('[data-reference-mode]').forEach(el=>el.onchange=e=>{const s=current().slides[+el.dataset.referenceMode];s.referenceMode=e.target.value;if(e.target.value==='manual_upload')s.pinterestPinId='';if(e.target.value==='editorial_direction_only'){s.pinterestPinId='';s.reference=null;s.referenceId=''}save(true);render()});$$('[data-assign-ref]').forEach(el=>el.onchange=e=>{const i=+el.dataset.assignRef,s=current().slides[i];s.reference=current().references.find(a=>a.id===e.target.value)||null;s.referenceId=e.target.value;s.referenceMode='manual_upload';s.pinterestPinId='';save(true);render()});$$('[data-assignment-direction]').forEach(el=>el.oninput=e=>{const s=current().slides[+el.dataset.assignmentDirection];s.direction=e.target.value;s.art=e.target.value;save()});
$$('[data-use-pin]').forEach(b=>b.onclick=()=>{const[i,id]=b.dataset.usePin.split(':'),s=current().slides[+i],rec=recommendPinsForSlide(current().pinterestPins,s,current()).find(x=>x.pin.id===id);s.referenceMode='pinterest_selected';s.pinterestPinId=id;s.pinterestMatchScore=rec?.score??null;s.pinterestMatchReason=rec?.reason||'Selected by the user from the Pinterest library.';s.reference=null;s.referenceId='';save(true);render();toast(`Pinterest reference selected for Slide ${n(+i)}.`)});$$('[data-lock-ref]').forEach(b=>b.onclick=()=>{const s=current().slides[+b.dataset.lockRef];s.referenceLocked=!s.referenceLocked;save(true);render()});$$('[data-clear-ref]').forEach(b=>b.onclick=()=>{const s=current().slides[+b.dataset.clearRef];s.reference=null;s.referenceId='';s.pinterestPinId='';s.referenceMode=current().pinterestConnected?'pinterest_auto':'editorial_direction_only';s.referenceLocked=false;save(true);render()});$('#recalculatePins')?.addEventListener('click',recalcSet);$('#pinSearch')?.addEventListener('input',e=>{state.pinterestSearch=e.target.value;render()});$('#pinFilter')?.addEventListener('change',e=>{state.pinterestFilter=e.target.value;render()});$('#importSnapshot')?.addEventListener('click',async()=>{try{await importSnapshotText($('#snapshotText').value)}catch(e){toast(e.message,'bad')}});$('#snapshotFile')?.addEventListener('change',async e=>{try{await importSnapshotText(await e.target.files[0].text())}catch(error){toast(error.message,'bad')}});$('#connectPinterest')?.addEventListener('click',async()=>{try{const res=await cloud.pinterestAction('authorize',{project_id:cloudState.project.id});if(res?.authorize_url)location.href=res.authorize_url;else toast(res?.message||'Pinterest OAuth is not configured yet. Snapshot import and Original Editorial Direction remain available.','bad')}catch(error){toast(`Pinterest OAuth is not configured yet (${error.message}). Snapshot import and Original Editorial Direction remain available.`,'bad')}});$('#syncPinterest')?.addEventListener('click',async()=>{try{const res=await cloud.pinterestAction('sync',{project_id:cloudState.project.id});const fresh=await cloud.loadProject(cloudState.project.id);state.storySets.forEach(set=>{set.pinterestPins=fresh.storySets[0]?.pinterestPins||[];set.pinterestConnected=true;set.pinterestSyncedAt=new Date().toISOString()});toast(`Synced ${res?.count??''} Pins from the board.`);recalcSet()}catch(error){toast(`Pinterest sync failed: ${error.message}`,'bad')}});$('#disconnectPinterest')?.addEventListener('click',async()=>{try{await cloud.pinterestAction('disconnect',{project_id:cloudState.project.id})}catch{}current().pinterestConnected=false;current().slides.forEach(s=>{if(!s.referenceLocked&&s.referenceMode==='pinterest_auto')s.referenceMode='editorial_direction_only'});save(true);render();toast('Pinterest disconnected. Cached Pins remain available until removed.')});
$('#copyFull')?.addEventListener('click',()=>cp(fullJson(),'Full story-set JSON copied.'));$('#downloadFull')?.addEventListener('click',()=>dl('bulk-story-set-prompt.json',fullJson()));$('#downloadZip')?.addEventListener('click',async()=>{try{dl(`LadyTin-${slug(current().title)}-bulk-generation-package.zip`,await makeZip(current().slides,current(),current().logo,false,cloud.resolveAssetBinary),'application/zip');toast('Story-set package downloaded.')}catch(e){console.error(e);toast(`Could not create the ZIP package: ${e.message}`,'bad')}});$('#downloadDraft')?.addEventListener('click',async()=>{try{dl(`LadyTin-${slug(current().title)}-incomplete-draft-package.zip`,await makeZip(current().slides,current(),current().logo,true,cloud.resolveAssetBinary),'application/zip');toast('Incomplete draft package downloaded.')}catch(e){console.error(e);toast(`Could not create the ZIP package: ${e.message}`,'bad')}});$$('[data-action]').forEach(b=>b.onclick=async()=>{const i=+b.dataset.i,s=current().slides[i],json=pretty(slidePrompt(s,i,current().slides,current(),current().logo));try{if(b.dataset.action==='copyPrompt'||b.dataset.action==='copy')cp(json,b.dataset.action==='copyPrompt'?'Prompt copied.':'Slide JSON copied.');if(b.dataset.action==='json')dl(`slide-${n(i)}-prompt.json`,json);if(b.dataset.action==='view')$('#json-'+i).open=!$('#json-'+i).open;if(b.dataset.action==='recalculate'){s.referenceLocked=false;const item=buildReferencePlan(current(),current().pinterestPins).slides[i];if(item?.selected_pin){s.referenceMode='pinterest_auto';s.pinterestPinId=item.selected_pin.id;s.pinterestMatchScore=item.recommendations[0]?.score||null;s.pinterestMatchReason=item.recommendations[0]?.reason||''}else{s.referenceMode='editorial_direction_only';s.pinterestPinId=''}save(true);render()}if(b.dataset.action==='package')dl(`LadyTin-${slug(current().title)}-slide-${n(i)}-package.zip`,await makeSlideZip(s,i,current().slides,current(),current().logo,cloud.resolveAssetBinary),'application/zip')}catch(e){console.error(e);toast(`Could not create the ZIP package: ${e.message}`,'bad')}})
wireCloudTopbar()}

// ---------- cloud wiring ----------
function wireAuth(){
$('#sendLink')?.addEventListener('click',async()=>{const email=$('#authEmail')?.value.trim();if(!email)return toast('Enter your email address.','bad');cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_LOADING'});render();try{await cloud.sendMagicLink(email);cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_LINK_SENT'})}catch(error){cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_ERROR',error:error.message})}render()});
$('#authEmail')?.addEventListener('keydown',e=>{if(e.key==='Enter')$('#sendLink')?.click()});
}
function wireProjects(){
$('#newProject')?.addEventListener('click',async()=>{const title=prompt('Project title','New LadyTin Project');if(!title)return;try{const p=await cloud.createProject(title,cloudState.auth.user);toast('Project created.');await openProject(p.id)}catch(error){toast(error.message,'bad')}});
$('#signOut')?.addEventListener('click',doSignOut);
$('#migrateLocal')?.addEventListener('click',async()=>{toast('Importing browser project…');try{const result=await cloud.migrateLocalProject(cloudState.auth.user,stored,stored.storySets);cloudState.migrationResult=result;if(result.ok){toast('Browser project imported.');if(result.warnings.length)toast(`${result.warnings.length} file${result.warnings.length===1?'':'s'} need re-uploading — see the notes below.`,'bad');cloudState.projects=await cloud.listProjects();render()}else toast(result.reason,'bad')}catch(error){toast(`Migration failed: ${error.message}`,'bad')}});
$$('[data-open-project]').forEach(b=>b.onclick=()=>openProject(b.dataset.openProject));
$$('[data-rename-project]').forEach(b=>b.onclick=async()=>{const p=cloudState.projects.find(x=>x.id===b.dataset.renameProject);const title=prompt('Rename project',p?.title||'');if(!title)return;try{await cloud.renameProject(b.dataset.renameProject,title);cloudState.projects=await cloud.listProjects();render()}catch(error){toast(error.message,'bad')}});
$$('[data-delete-project]').forEach(b=>b.onclick=async()=>{const p=cloudState.projects.find(x=>x.id===b.dataset.deleteProject);if(!confirm(`Delete "${p?.title}" permanently, including its story sets, slides and files?`))return;try{await cloud.deleteProject(b.dataset.deleteProject);cloudState.projects=await cloud.listProjects();toast('Project deleted.');render()}catch(error){toast(error.message,'bad')}});
}
function wireCloudTopbar(){
$('#backProjects')?.addEventListener('click',async()=>{await flushNow();history.pushState({},'','/');await showProjects()});
$('#signOut')?.addEventListener('click',doSignOut);
$('#shareProject')?.addEventListener('click',async()=>{cloudState.shareOpen=true;try{cloudState.members=await cloud.listMembers(cloudState.project.id);cloudState.invites=await cloud.listInvites(cloudState.project.id)}catch{}render()});
$('#closeShare')?.addEventListener('click',()=>{cloudState.shareOpen=false;cloudState.lastInvite=null;render()});
$('#createInvite')?.addEventListener('click',async()=>{const email=$('#inviteEmail')?.value.trim(),role=$('#inviteRole')?.value||'viewer';if(!email)return toast('Enter the collaborator’s email.','bad');try{cloudState.lastInvite=await cloud.createInvite(cloudState.project.id,email,role,cloudState.auth.user.id);cloudState.invites=await cloud.listInvites(cloudState.project.id);toast('Invitation created. Share the link below.');render()}catch(error){toast(error.message,'bad')}});
$('#copyInvite')?.addEventListener('click',()=>cp(cloudState.lastInvite?.url||'','Invite link copied.'));
$$('[data-member-role]').forEach(el=>el.onchange=async e=>{try{await cloud.changeMemberRole(cloudState.project.id,el.dataset.memberRole,e.target.value);cloudState.members=await cloud.listMembers(cloudState.project.id);toast('Role updated.');render()}catch(error){toast(error.message,'bad')}});
$$('[data-remove-member]').forEach(b=>b.onclick=async()=>{if(!confirm('Remove this member from the project?'))return;try{await cloud.removeMember(cloudState.project.id,b.dataset.removeMember);cloudState.members=await cloud.listMembers(cloudState.project.id);toast('Member removed.');render()}catch(error){toast(error.message,'bad')}});
$('#conflictReload')?.addEventListener('click',async()=>{const c=cloudState.conflict;cloudState.conflict=null;if(c?.kind==='slide'&&c.remote){const set=state.storySets.find(s=>s.id===c.setId);const i=set?.slides.findIndex(s=>s.id===c.id);if(set&&i>-1){const assetsById={};[...set.mainAssets,...set.references,...(set.logo?[set.logo]:[])].forEach(a=>assetsById[a.id]=a);set.slides[i]=normaliseSlide(rowToSlide(c.remote,assetsById),i,set);set.slides[i].revision=Number(c.remote.revision)||1;snapEntity('slide',c.id,slideToRow(set.slides[i],set.id),set.slides[i].revision,set.id)}}if(c?.kind==='story_set'&&c.remote){const set=state.storySets.find(s=>s.id===c.id);if(set)Object.assign(set,{title:c.remote.title,overallDirection:c.remote.overallDirection,rawStorySetCopy:c.remote.rawStorySetCopy,revision:c.remote.revision})}cloudState.saveState='saved';render()});
$('#conflictOverwrite')?.addEventListener('click',async()=>{const c=cloudState.conflict;cloudState.conflict=null;try{if(c?.kind==='slide'){const result=await cloud.overwriteSlide(c.id,c.localRow);if(!result.conflict){const set=state.storySets.find(s=>s.id===c.setId);const s=set?.slides.find(x=>x.id===c.id);if(s){s.revision=result.row.revision;snapEntity('slide',c.id,slideToRow(s,set.id),s.revision,set.id)}}}if(c?.kind==='story_set'){const set=state.storySets.find(s=>s.id===c.id);if(set){const remoteRev=(await cloud.updateStorySetGuarded(set.id,c.remote?.revision||1,storySetToRow(set,cloudState.project.id)));if(!remoteRev.conflict){set.revision=remoteRev.row.revision;snapEntity('story_set',set.id,storySetToRow(set,cloudState.project.id),set.revision)}}}toast('Your version was saved.');cloudState.saveState='saved'}catch(error){toast(error.message,'bad')}render()});
}
async function flushNow(){clearTimeout(saveTimer);if(editable())await flushSync()}
async function doSignOut(){await flushNow();unsubscribeAll();await cloud.signOut();history.pushState({},'','/');cloudState.project=null;cloudState.view='auth';cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_SIGNED_OUT'});render()}

// ---------- realtime ----------
function assetsIndex(){const map={};for(const set of state.storySets)for(const a of[...set.mainAssets,...set.references,...(set.logo?[set.logo]:[])])map[a.id]=a;return map}
function onRealtimeEvent(ev){
  if(cloudState.view!=='studio')return;
  if(ev.table==='project_members'){cloud.listMembers(cloudState.project.id).then(m=>{cloudState.members=m;const mine=m.find(x=>x.user_id===cloudState.auth.user?.id);if(!mine){toast('You were removed from this project.','bad');history.pushState({},'','/');return showProjects()}if(mine.role!==cloudState.role){cloudState.role=mine.role;render()}}).catch(()=>{});return}
  const applied=applyRealtimeEvent({project:cloudState.project,storySets:state.storySets},ev,assetsIndex());
  if(applied.deleted){toast('This project was deleted by its owner.','bad');history.pushState({},'','/');return showProjects()}
  cloudState.project=applied.project;state.storySets=applied.storySets;
  if(ev.table==='story_sets'&&ev.row?.id){const s=state.storySets.find(x=>x.id===ev.row.id);if(s)snapEntity('story_set',s.id,storySetToRow(s,cloudState.project.id),s.revision)}
  if(ev.table==='slides'&&ev.row?.id){const set=state.storySets.find(x=>x.id===ev.row.story_set_id);const s=set?.slides.find(x=>x.id===ev.row.id);if(s)snapEntity('slide',s.id,slideToRow(s,set.id),s.revision,set.id)}
  if(ev.table==='story_sets'&&ev.type==='INSERT')resubscribe();
  if(!state.storySets.length)state.storySets=[defaultSet()];
  state.activeSet=Math.min(state.activeSet,state.storySets.length-1);
  state.selectedSlide=Math.min(state.selectedSlide,(current()?.slides.length||1)-1);
  render();
}
function resubscribe(){if(!cloudState.project)return;subscribeToProject(cloudState.project.id,state.storySets.map(s=>s.id).filter(isUuid),onRealtimeEvent)}

// ---------- project lifecycle ----------
function routeProjectId(){const m=location.pathname.match(/^\/project\/([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i);return m?m[1]:null}
async function openProject(projectId,push=true){
  try{
    cloudState.view='loadingProject';render();
    const hydrated=await cloud.loadProject(projectId);
    cloudState.project=hydrated.project;
    cloudState.role=(await cloud.myRole(projectId,cloudState.auth.user.id))||'viewer';
    cloudState.members=await cloud.listMembers(projectId);
    cloudState.conflict=null;cloudState.shareOpen=false;cloudState.lastInvite=null;
    state.storySets=(hydrated.storySets.length?hydrated.storySets:[]).map(s=>{const set=normaliseSet(s);set.cloudId=set.id;set.revision=s.revision;set.slides.forEach((sl,i)=>{const src=s.slides[i];if(src){sl.revision=src.revision;sl.storySetId=src.storySetId}});return set});
    if(!state.storySets.length)state.storySets=[defaultSet()];
    state.activeSet=0;state.selectedSlide=0;state.rawInput=state.storySets[0]?.rawStorySetCopy||'';state.parseReview=null;
    rebuildSnapshot();
    cloudState.view='studio';
    resubscribe();
    joinPresence(projectId,{user_id:cloudState.auth.user.id,name:cloudState.auth.user.email?.split('@')[0]||'Collaborator',activity:'viewing',context:steps[state.activeStep]},list=>{cloudState.presence=list;if(cloudState.view==='studio')render()});
    if(push)history.pushState({},'',`/project/${projectId}`);
    render();
  }catch(error){
    console.error(error);
    toast(`Could not open the project: ${error.message}`,'bad');
    await showProjects();
  }
}
async function showProjects(){
  unsubscribeAll();
  cloudState.view='projects';cloudState.project=null;cloudState.presence=[];
  try{cloudState.projects=await cloud.listProjects()}catch(error){toast(error.message,'bad')}
  render();
}

// ---------- boot ----------
async function handlePinterestCallback(){
  const url=new URL(location.href);
  if(!location.pathname.startsWith('/project/pinterest/callback'))return false;
  const code=url.searchParams.get('code'),oauthState=url.searchParams.get('state');
  try{const res=await cloud.pinterestAction('callback',{code,state:oauthState});toast('Pinterest connected.');history.replaceState({},'','/'+(res?.project_id?`project/${res.project_id}`:''));if(res?.project_id){await openProject(res.project_id,false);return true}}
  catch(error){toast(`Pinterest connection failed: ${error.message}`,'bad');history.replaceState({},'','/')}
  return false;
}
async function handleAuthSession(session){
  if(session?.user){
    const alreadyIn=cloudState.auth.user?.id===session.user.id&&['studio','projects','loadingProject'].includes(cloudState.view);
    cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_SIGNED_IN',user:session.user});
    if(alreadyIn)return;
    cloud.ensureProfile(session.user);
    if(cloudState.inviteToken){
      const token=cloudState.inviteToken;cloudState.inviteToken=null;history.replaceState({},'','/');
      try{const res=await cloud.acceptInvite(token);toast('Invitation accepted. Welcome to the project.');if(res?.project_id)return openProject(res.project_id)}catch(error){toast(error.message,'bad')}
    }
    if(await handlePinterestCallback())return;
    const routed=routeProjectId();
    if(routed)return openProject(routed,false);
    return showProjects();
  }
  unsubscribeAll();
  cloudState.auth=authReducer(cloudState.auth,{type:'AUTH_SIGNED_OUT'});
  cloudState.view='auth';render();
}
let presenceEditTimer=null;
document.addEventListener('input',()=>{
  if(cloudState.view!=='studio')return;
  const context=state.activeStep===1?`Slide ${n(Math.min(state.selectedSlide,current().slides.length-1))}`:steps[state.activeStep];
  updatePresence({activity:'editing',context});
  clearTimeout(presenceEditTimer);
  presenceEditTimer=setTimeout(()=>updatePresence({activity:'viewing',context}),6000);
},true);
window.addEventListener('popstate',()=>{
  if(!cloudState.auth.user)return;
  const id=routeProjectId();
  if(id)openProject(id,false);else showProjects();
});
window.addEventListener('beforeunload',()=>{if(editable())savePrefs()});
async function boot(){
  if(!isConfigured()){cloudState.view='config';return render()}
  const url=new URL(location.href);
  const invite=url.searchParams.get('invite');
  if(invite)cloudState.inviteToken=invite;
  cloudState.view='loading';render();
  supabase.auth.onAuthStateChange((_event,session)=>{handleAuthSession(session)});
  const{data}=await supabase.auth.getSession();
  await handleAuthSession(data?.session||null);
}
boot();
